/**
 * Defines the arguments for the `itemClick` event of the PanelBar.
 */
export class PanelBarItemClickEvent {
    /**
     * Defines the clicked item.
     */
    item;
    /**
     * Defines the DOM event that triggered the `itemClick` event.
     */
    originalEvent;
}
